def _parse_gs_uri(uri: str):
    m = re.match(r"^gs://([^/]+)/(.+)$", uri or "")
    if not m:
        return None, None
    return m.group(1), m.group(2)


def _safe_filename(name: str) -> str:
    name = (name or "").strip().replace("\\", "/")
    name = name.split("/")[-1]
    name = re.sub(r"[^A-Za-z0-9._-]+", "_", name)
